namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-option" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)"
                title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "🚀"];
}

@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <span class="channel-description">@TruncateDescription(channel.Description)</span>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int? ActiveChannelId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        const int maxLength = 50;
        return description.Length <= maxLength
            ? description
            : string.Concat(description.AsSpan(0, maxLength), "…");
    }
}

@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services

<div class="message-item @(_showActions ? "hovered" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReaction.InvokeAsync(reaction.Emoji)"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public int ThreadReplyCount { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnReaction { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void OnMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnReaction.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services
@inject IJSRuntime JS

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
            @if (_isLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @foreach (var message in Messages)
            {
                <MessageItem Message="message"
                             ThreadReplyCount="GetThreadReplyCount(message.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReaction="(emoji) => OnReaction.InvokeAsync((message.Id, emoji))" />
            }
        </div>

        <div class="message-input-area">
            <textarea @bind="NewMessageText" @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Message #@Channel.Name"
                      rows="2"></textarea>
            <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessageText)">
                Send
            </button>
        </div>
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter]
    public Channel? Channel { get; set; }

    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter, EditorRequired]
    public List<ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int MessageId, string Emoji)> OnReaction { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private string NewMessageText { get; set; } = "";
    private bool _isLoadingMore;

    private int GetThreadReplyCount(int messageId)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
        return summary?.ReplyCount ?? 0;
    }

    private async Task HandleScroll()
    {
        if (_isLoadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            _isLoadingMore = true;
            await OnLoadMore.InvokeAsync();
            _isLoadingMore = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(NewMessageText)) return;
        var text = NewMessageText;
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
    }
}

@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="message-header">
                <span class="message-author">@RootMessage.Author</span>
                <span class="message-time">@FormatRelativeTime(RootMessage.SentAt)</span>
            </div>
            <div class="message-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <div class="thread-input-area">
            <textarea @bind="ReplyText" @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Reply…"
                      rows="2"></textarea>
            <button class="send-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(ReplyText)">
                Reply
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message? RootMessage { get; set; }

    [Parameter, EditorRequired]
    public List<Message> Replies { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendReply { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnClose { get; set; }

    private string ReplyText { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(ReplyText)) return;
        var text = ReplyText;
        ReplyText = "";
        await OnSendReply.InvokeAsync(text);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

