@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <span class="channel-description">@TruncateDescription(channel.Description)</span>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Channel> Channels { get; set; } = [];

    [Parameter]
    public int? ActiveChannelId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnChannelSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        const int maxLength = 50;
        return description.Length <= maxLength
            ? description
            : string.Concat(description.AsSpan(0, maxLength), "…");
    }
}

@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services

<div class="message-item @(_showActions ? "hovered" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReaction.InvokeAsync(reaction.Emoji)"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public int ThreadReplyCount { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnReaction { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void OnMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnReaction.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

