@namespace sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services
@inject IJSRuntime JS

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
            @if (_isLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @foreach (var message in Messages)
            {
                <MessageItem Message="message"
                             ThreadReplyCount="GetThreadReplyCount(message.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReaction="(emoji) => OnReaction.InvokeAsync((message.Id, emoji))" />
            }
        </div>

        <div class="message-input-area">
            <textarea @bind="NewMessageText" @bind:event="oninput"
                      @onkeydown="HandleKeyDown"
                      placeholder="Message #@Channel.Name"
                      rows="2"></textarea>
            <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(NewMessageText)">
                Send
            </button>
        </div>
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter]
    public Channel? Channel { get; set; }

    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter, EditorRequired]
    public List<ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int MessageId, string Emoji)> OnReaction { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private string NewMessageText { get; set; } = "";
    private bool _isLoadingMore;

    private int GetThreadReplyCount(int messageId)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
        return summary?.ReplyCount ?? 0;
    }

    private async Task HandleScroll()
    {
        if (_isLoadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            _isLoadingMore = true;
            await OnLoadMore.InvokeAsync();
            _isLoadingMore = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(NewMessageText)) return;
        var text = NewMessageText;
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
    }
}

