@page "/chat"
@rendermode InteractiveServer
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Components.Chat
@using sv_2810ea54c4534b4c9b62da08e7fa3df0.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <MessageArea Channel="_activeChannel"
                 Messages="_messages"
                 ThreadSummaries="_threadSummaries"
                 OnOpenThread="OpenThread"
                 OnReaction="HandleReaction"
                 OnSendMessage="SendMessage"
                 OnLoadMore="LoadOlderMessages"
                 class="@(_threadOpen ? "" : "expanded")" />

    @if (_threadOpen)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnSendReply="SendThreadReply"
                     OnClose="CloseThread" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<ThreadSummary> _threadSummaries = [];
    private int? _activeChannelId;
    private Channel? _activeChannel;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        _channels = await ChatService.GetChannelsAsync();

        CloseThread();
    }

    private async Task LoadOlderMessages()
    {
        if (_activeChannelId is null) return;

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannelId is null) return;

        var message = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(message);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to show updated reactions
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messages.Count);
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        BuildThreadSummaries();
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private void BuildThreadSummaries()
    {
        // Build summaries from messages that have replies
        var replyGroups = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value);

        _threadSummaries = replyGroups.Select(g => new ThreadSummary(
            RootMessageId: g.Key,
            ReplyCount: g.Count(),
            LastReplyAt: g.Max(m => m.SentAt)
        )).ToList();
    }
}

/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ===== Channel Sidebar ===== */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

::deep .sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #333;
}

::deep .sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

::deep .channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    padding: 8px 16px;
    cursor: pointer;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background: #27292d;
}

::deep .channel-item.active {
    background: #1164a3;
    color: #fff;
}

::deep .channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .unread-badge {
    background: #e01e5a;
    color: #fff;
    border-radius: 10px;
    padding: 1px 7px;
    font-size: 0.75rem;
    font-weight: 700;
    min-width: 18px;
    text-align: center;
}

::deep .channel-description {
    font-size: 0.8rem;
    color: #999;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .channel-item.active .channel-description {
    color: rgba(255, 255, 255, 0.7);
}

/* ===== Message Area ===== */
::deep .message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.2s ease;
}

::deep .message-area.expanded {
    width: 80%;
}

::deep .message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e4e8;
    flex-shrink: 0;
}

::deep .message-area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
}

::deep .message-area-header p {
    margin: 2px 0 0;
    font-size: 0.85rem;
    color: #666;
}

::deep .no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

/* ===== Message List ===== */
::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

::deep .loading-indicator {
    text-align: center;
    color: #999;
    padding: 8px;
    font-size: 0.85rem;
}

/* ===== Message Item ===== */
::deep .message-item {
    padding: 8px 12px;
    border-radius: 6px;
    position: relative;
    margin-bottom: 2px;
    transition: background-color 0.1s;
}

::deep .message-item.hovered {
    background: #f8f9fa;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .message-author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1d1c1d;
}

::deep .message-time {
    font-size: 0.75rem;
    color: #999;
}

::deep .message-content {
    font-size: 0.95rem;
    color: #1d1c1d;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ===== Reactions ===== */
::deep .reaction-row {
    display: flex;
    gap: 4px;
    margin-top: 6px;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    background: #f0f4ff;
    border: 1px solid #d0d8e8;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
    display: flex;
    align-items: center;
    gap: 4px;
}

::deep .reaction-badge:hover {
    background: #dce4f5;
}

/* ===== Thread Link ===== */
::deep .thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0 0;
    display: block;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* ===== Message Actions (hover) ===== */
::deep .message-actions {
    position: absolute;
    top: -4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

::deep .action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
    color: #555;
    white-space: nowrap;
}

::deep .action-btn:hover {
