toolArgs.file_text:
/* ===== Chat Layout ===== */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

/* ===== Channel Sidebar ===== */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1a1d21;
    color: #ccc;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

::deep .sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #333;
}

::deep .sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

::deep .channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    padding: 8px 16px;
    cursor: pointer;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background: #27292d;
}

::deep .channel-item.active {
    background: #1164a3;
    color: #fff;
}

::deep .channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

::deep .unread-badge {
    background: #e01e5a;
    color: #fff;
    border-radius: 10px;
    padding: 1px 7px;
    font-size: 0.75rem;
    font-weight: 700;
    min-width: 18px;
    text-align: center;
}

::deep .channel-description {
    font-size: 0.8rem;
    color: #999;
    display: block;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .channel-item.active .channel-description {
    color: rgba(255, 255, 255, 0.7);
}

/* ===== Message Area ===== */
::deep .message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.2s ease;
}

::deep .message-area.expanded {
    width: 80%;
}

::deep .message-area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e4e8;
    flex-shrink: 0;
}

::deep .message-area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
}

::deep .message-area-header p {
    margin: 2px 0 0;
    font-size: 0.85rem;
    color: #666;
}

::deep .no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

/* ===== Message List ===== */
::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

::deep .loading-indicator {
    text-align: center;
    color: #999;
    padding: 8px;
    font-size: 0.85rem;
}

/* ===== Message Item ===== */
::deep .message-item {
    padding: 8px 12px;
    border-radius: 6px;
    position: relative;
    margin-bottom: 2px;
    transition: background-color 0.1s;
}

::deep .message-item.hovered {
    background: #f8f9fa;
}

::deep .message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .message-author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1d1c1d;
}

::deep .message-time {
    font-size: 0.75rem;
    color: #999;
}

::deep .message-content {
    font-size: 0.95rem;
    color: #1d1c1d;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ===== Reactions ===== */
::deep .reaction-row {
    display: flex;
    gap: 4px;
    margin-top: 6px;
    flex-wrap: wrap;
}

::deep .reaction-badge {
    background: #f0f4ff;
    border: 1px solid #d0d8e8;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
    display: flex;
    align-items: center;
    gap: 4px;
}

::deep .reaction-badge:hover {
    background: #dce4f5;
}

/* ===== Thread Link ===== */
::deep .thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0 0;
    display: block;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* ===== Message Actions (hover) ===== */
::deep .message-actions {
    position: absolute;
    top: -4px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

::deep .action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
    color: #555;
    white-space: nowrap;
}

::deep .action-btn:hover {
    background: #f0f0f0;
}

/* ===== Emoji Picker ===== */
::deep .emoji-picker {
    position: absolute;
    top: -44px;
    right: 8px;
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 8px;
    padding: 6px;
    display: flex;
    gap: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 10;
}

::deep .emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

::deep .emoji-option:hover {
    background: #f0f0f0;
}

/* ===== Message Input ===== */
::deep .message-input-area,
::deep .thread-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e1e4e8;
    align-items: flex-end;
    flex-shrink: 0;
}

::deep .message-input-area textarea,
::deep .thread-input-area textarea {
    flex: 1;
    border: 1px solid #d0d4d8;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 0.95rem;
    resize: none;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

::deep .message-input-area textarea:focus,
::deep .thread-input-area textarea:focus {
    border-color: #1264a3;
}

::deep .send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 16px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    white-space: nowrap;
    transition: background 0.15s;
}

::deep .send-btn:hover:not(:disabled) {
    background: #006a4e;
}

::deep .send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ===== Thread Panel ===== */
::deep .thread-panel {
    width: 25%;
    min-width: 280px;
    background: #fff;
    border-left: 1px solid #e1e4e8;
    display: flex;
    flex-direction: column;
}

::deep .thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e1e4e8;
    flex-shrink: 0;
}

::deep .thread-header h3 {
    margin: 0;
    font-size: 1.05rem;
    font-weight: 700;
}

::deep .close-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

::deep .close-btn:hover {
    background: #f0f0f0;
}

::deep .thread-root-message {
    padding: 12px 16px;
    background: #f8f9fa;
    border-bottom: 1px solid #e1e4e8;
    flex-shrink: 0;
}

::deep .thread-divider {
    padding: 8px 16px;
    font-size: 0.8rem;
    color: #999;
    border-bottom: 1px solid #e1e4e8;
    flex-shrink: 0;
}

::deep .thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

::deep .thread-reply {
    padding: 8px 0;
    border-bottom: 1px solid #f0f0f0;
}

::deep .thread-reply:last-child {
    border-bottom: none;
}

